app.post('/token', async (req, res) => {
    const grant_type = req.body.grant_type;
    const code = req.body.code;

    // Check if the grant type is refresh token
    if (grant_type === 'refresh_token') {
        // Get the refresh token from Redis
        const refreshToken = await RefreshToken.findOne({ where: { id: code } });
        if (!refreshToken) {
            return res.status(401).send('Unauthorized');
        }

        // Generate a new access token and refresh token for the user
        const accessToken = await oauthServer.generateAccessToken(refreshToken.client_id, refreshToken.user_id);
        const newRefreshToken = new RefreshToken({ client_id: refreshToken.client_id, user_id: refreshToken.user_id, token: generateRefreshToken() });

        // Save the new access token and refresh token to the database
        await oauthServer.saveAccessToken(accessToken);
        await oauthServer.saveRefreshToken(newRefreshToken);

        // Return the new access token and refresh token to the client
        res.json({ access_token: accessToken.token, refresh_token: newRefreshToken.token });
    } else {
        return res.status(401).send('Unauthorized');
    }
});

// Function to generate a random refresh token
function generateRefreshToken() {
    const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let refreshToken = '';
    for (let i = 0; i < 32; i++) {
        refreshToken += characters.charAt(Math.floor(Math.random() * characters.length));
    }
    return refreshToken;
}

